compliant:
public void RunCommand(string filename)
{
    // Compliant: validate and sanitize input
    string safeFilename = Path.GetFileName(filename); // Only filename, no path
    if (!IsValidFilename(safeFilename))
    {
        throw new ArgumentException("Invalid filename");
    }
    var process = new Process();
    process.StartInfo.FileName = "del";
    process.StartInfo.Arguments = safeFilename;
    process.Start();
}
